import React from 'react';
import { Routes, Route } from 'react-router-dom';
import './App.css';

// Temporary minimal components
const Header = () => (
  <header className="header">
    <nav className="navbar">
      <div className="logo">Bike<span>Rental</span></div>
      <ul className="nav-links">
        <li><a href="/">Home</a></li>
        <li><a href="/bikes">Bikes</a></li>
        <li><a href="/manage-bookings">Bookings</a></li>
        <li><a href="/contact">Contact</a></li>
      </ul>
    </nav>
  </header>
);

const Footer = () => (
  <footer className="footer">
    <div className="footer-content">
      <div className="footer-section">
        <h3>BikeRental</h3>
        <p>Your trusted bike rental service</p>
      </div>
    </div>
    <div className="footer-bottom">
      <p>&copy; 2024 BikeRental. All rights reserved.</p>
    </div>
  </footer>
);

const Home = () => (
  <div className="section">
    <h1>Welcome to Bike Rental</h1>
    <p>This is a temporary home page.</p>
  </div>
);

const Bikes = () => (
  <div className="section">
    <h1>Our Bikes</h1>
    <p>Bike catalog will be here.</p>
  </div>
);

const Booking = () => (
  <div className="section">
    <h1>Book a Bike</h1>
    <p>Booking form will be here.</p>
  </div>
);

const BookingsManagement = () => (
  <div className="section">
    <h1>Manage Bookings</h1>
    <p>Bookings management will be here.</p>
  </div>
);

const Terms = () => (
  <div className="section">
    <h1>Terms & Conditions</h1>
    <p>Terms page will be here.</p>
  </div>
);

const Contact = () => (
  <div className="section">
    <h1>Contact Us</h1>
    <p>Contact form will be here.</p>
  </div>
);

function App() {
  return (
    <div className="App">
      <Header />
      <main className="main-content">
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/bikes" element={<Bikes />} />
          <Route path="/booking/:bikeId" element={<Booking />} />
          <Route path="/booking" element={<Booking />} />
          <Route path="/manage-bookings" element={<BookingsManagement />} />
          <Route path="/terms" element={<Terms />} />
          <Route path="/contact" element={<Contact />} />
        </Routes>
      </main>
      <Footer />
    </div>
  );
}

export default App;
